import React from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './context/AuthContext';
import { NavigationProvider } from './context/NavigationContext';
import Navbar from './components/Navbar';
import Notifications from './components/Notifications';
import Loading from './components/Loading';
import Home from './pages/Home';
import Login from './pages/Login';
import Register from './pages/Register';
import GameDetail from './pages/GameDetail';
import Cart from './pages/Cart';
import Profile from './pages/Profile';
import Favorites from './pages/Favorites';
import GoogleCallback from './pages/GoogleCallback';
import TestBackend from './pages/TestBackend';

const AdminDashboard = () => {
  const { state } = useAuth();
  const [games, setGames] = React.useState([
    {
      _id: '1',
      title: 'Fortnite - Account Level 150',
      description: 'حساب Fortnite بمستوى 150 مع شخصيات نادرة',
      price: 299.99,
      originalPrice: 399.99,
      discount: 25,
      category: 'battle-royale',
      platform: 'PC',
      image: 'https://via.placeholder.com/300x200/FF6B6B/FFFFFF?text=Fortnite',
      availability: 'available',
      region: 'Global',
      isNew: true
    },
    {
      _id: '2',
      title: 'PUBG Mobile - Account Level 100',
      description: 'حساب PUBG Mobile بمستوى 100 مع أسلحة نادرة',
      price: 199.99,
      category: 'battle-royale',
      platform: 'Mobile',
      image: 'https://via.placeholder.com/300x200/4ECDC4/FFFFFF?text=PUBG',
      availability: 'available',
      region: 'Global'
    },
    {
      _id: '3',
      title: 'Call of Duty - Premium Account',
      description: 'حساب COD مميز مع جميع الإضافات',
      price: 399.99,
      category: 'fps',
      platform: 'PC',
      image: 'https://via.placeholder.com/300x200/45B7D1/FFFFFF?text=COD',
      availability: 'available',
      region: 'Global'
    },
    {
      _id: '4',
      title: 'GTA V Online - Modded Account',
      description: 'حساب GTA V Online معدل مع ملايين',
      price: 149.99,
      originalPrice: 249.99,
      discount: 40,
      category: 'open-world',
      platform: 'PC',
      image: 'https://via.placeholder.com/300x200/96CEB4/FFFFFF?text=GTA',
      availability: 'available',
      region: 'Global',
      isNew: true
    }
  ]);
  const [loading, setLoading] = React.useState(false);
  const [activeTab, setActiveTab] = React.useState('games');
  const [searchQuery, setSearchQuery] = React.useState('');
  const [platformFilter, setPlatformFilter] = React.useState('all');
  const [showAddForm, setShowAddForm] = React.useState(false);
  const [gameForm, setGameForm] = React.useState({
    title: '',
    description: '',
    price: '',
    platform: 'PC',
    availability: 'available'
  });

  React.useEffect(() => {
    if (state.isAuthenticated && state.user?.role === 'admin') {
      fetchGames();
    }
  }, [state.isAuthenticated]);

  const fetchGames = async () => {
    setLoading(true);
    setTimeout(() => {
      setLoading(false);
    }, 1000);
  };

  const handleAddGame = (e: any) => {
    e.preventDefault();
    alert('تمت إضافة اللعبة بنجاح!');
    setShowAddForm(false);
    setGameForm({
      title: '',
      description: '',
      price: '',
      platform: 'PC',
      availability: 'available'
    });
  };

  const handleEditPrice = (gameId) => {
    const newPrice = prompt('أدخل السعر الجديد:');
    if (newPrice) {
      alert('تم تحديث السعر بنجاح!');
    }
  };

  const handleAddDiscount = (gameId) => {
    const discount = prompt('أدخل نسبة الخصم:');
    if (discount) {
      alert(`تم إضافة خصم ${discount}% بنجاح!`);
    }
  };

  const handleDeleteGame = (gameId) => {
    if (window.confirm('هل أنت متأكد من حذف هذه اللعبة؟')) {
      alert('تم حذف اللعبة بنجاح!');
    }
  };

  if (!state.isAuthenticated || state.user?.role !== 'admin') {
    return (
      <div style={{ minHeight: '100vh', backgroundColor: '#111827', color: 'white', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
        <div style={{ textAlign: 'center' }}>
          <h1 style={{ fontSize: '2.5rem', fontWeight: 'bold', marginBottom: '1rem' }}>غير مصرح بالوصول</h1>
          <p style={{ fontSize: '1.25rem', marginBottom: '2rem' }}>يجب تسجيل الدخول كمدير للوصول إلى هذه الصفحة</p>
          <Navigate to="/login" replace />
        </div>
      </div>
    );
  }

  return (
    <div style={{ minHeight: '100vh', backgroundColor: '#111827', color: 'white', padding: '1.5rem' }}>
      <div style={{ maxWidth: '1280px', margin: '0 auto' }}>
        <div style={{ marginBottom: '2rem' }}>
          <h1 style={{ fontSize: '2.5rem', fontWeight: 'bold', marginBottom: '0.5rem' }}>لوحة تحكم الإدمن</h1>
          <p style={{ color: '#9CA3AF' }}>مرحباً Admin</p>
        </div>

        <div style={{ marginBottom: '1.5rem' }}>
          <nav style={{ display: 'flex', gap: '1rem' }}>
            <button
              onClick={() => setActiveTab('games')}
              style={{
                padding: '0.5rem 1rem',
                borderRadius: '0.5rem',
                fontWeight: 'medium',
                backgroundColor: activeTab === 'games' ? '#DC2626' : '#374151',
                color: 'white',
                border: 'none',
                cursor: 'pointer'
              }}
            >
              إدارة الألعاب
            </button>
            <button
              onClick={() => setActiveTab('users')}
              style={{
                padding: '0.5rem 1rem',
                borderRadius: '0.5rem',
                fontWeight: 'medium',
                backgroundColor: activeTab === 'users' ? '#DC2626' : '#374151',
                color: 'white',
                border: 'none',
                cursor: 'pointer'
              }}
            >
              إدارة المستخدمين
            </button>
            <button
              onClick={() => setActiveTab('orders')}
              style={{
                padding: '0.5rem 1rem',
                borderRadius: '0.5rem',
                fontWeight: 'medium',
                backgroundColor: activeTab === 'orders' ? '#DC2626' : '#374151',
                color: 'white',
                border: 'none',
                cursor: 'pointer'
              }}
            >
              إدارة الطلبات
            </button>
          </nav>
        </div>

        {activeTab === 'games' && (
          <div>
            <div style={{ marginBottom: '1.5rem', display: 'flex', flexDirection: 'column', gap: '1rem', alignItems: 'stretch' }}>
              <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                <div style={{ position: 'relative' }}>
                  <input
                    type="text"
                    placeholder="البحث عن لعبة..."
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    style={{
                      paddingLeft: '2.5rem',
                      paddingRight: '1rem',
                      padding: '0.5rem',
                      backgroundColor: '#374151',
                      color: 'white',
                      borderRadius: '0.5rem',
                      border: 'none',
                      width: '100%',
                      maxWidth: '16rem'
                    }}
                  />
                  <svg
                    style={{ position: 'absolute', right: '0.75rem', top: '0.625rem', width: '1.25rem', height: '1.25rem', color: '#9CA3AF' }}
                    fill="none"
                    stroke="currentColor"
                    viewBox="0 0 24 24"
                  >
                    <path
                      strokeLinecap="round"
                      strokeLinejoin="round"
                      strokeWidth={2}
                      d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z"
                    />
                  </svg>
                </div>
                <select
                  value={platformFilter}
                  onChange={(e) => setPlatformFilter(e.target.value)}
                  style={{
                    padding: '0.5rem 1rem',
                    backgroundColor: '#374151',
                    color: 'white',
                    borderRadius: '0.5rem',
                    border: 'none'
                  }}
                >
                  <option value="all">جميع المنصات</option>
                  <option value="PC">PC</option>
                  <option value="Mobile">Mobile</option>
                  <option value="Console">Console</option>
                </select>
              </div>
              <button
                onClick={() => setShowAddForm(!showAddForm)}
                style={{
                  backgroundColor: '#DC2626',
                  color: 'white',
                  padding: '0.5rem 1rem',
                  borderRadius: '0.5rem',
                  fontWeight: 'medium',
                  border: 'none',
                  cursor: 'pointer'
                }}
              >
                {showAddForm ? 'إلغاء' : '+ إضافة لعبة جديدة'}
              </button>
            </div>

            {showAddForm && (
              <div style={{ marginBottom: '1.5rem', backgroundColor: '#1F2937', padding: '1.5rem', borderRadius: '0.5rem' }}>
                <h2 style={{ fontSize: '1.25rem', fontWeight: 'bold', marginBottom: '1rem' }}>إضافة لعبة جديدة</h2>
                <form onSubmit={handleAddGame} style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                  <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '1rem' }}>
                    <div>
                      <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 'medium', marginBottom: '0.5rem' }}>اسم اللعبة</label>
                      <input
                        type="text"
                        value={gameForm.title}
                        onChange={(e) => setGameForm({...gameForm, title: e.target.value})}
                        style={{ width: '100%', padding: '0.5rem 0.75rem', backgroundColor: '#374151', color: 'white', borderRadius: '0.375rem', border: 'none' }}
                        required
                      />
                    </div>
                    <div>
                      <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 'medium', marginBottom: '0.5rem' }}>السعر</label>
                      <input
                        type="number"
                        value={gameForm.price}
                        onChange={(e) => setGameForm({...gameForm, price: e.target.value})}
                        style={{ width: '100%', padding: '0.5rem 0.75rem', backgroundColor: '#374151', color: 'white', borderRadius: '0.375rem', border: 'none' }}
                        required
                      />
                    </div>
                  </div>
                  <div>
                    <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 'medium', marginBottom: '0.5rem' }}>الوصف</label>
                    <textarea
                      value={gameForm.description}
                      onChange={(e) => setGameForm({...gameForm, description: e.target.value})}
                      style={{ width: '100%', padding: '0.5rem 0.75rem', backgroundColor: '#374151', color: 'white', borderRadius: '0.375rem', border: 'none' }}
                      rows={4}
                      required
                    />
                  </div>
                  <div>
                    <label style={{ display: 'block', fontSize: '0.875rem', fontWeight: 'medium', marginBottom: '0.5rem' }}>المنصة</label>
                    <select
                      value={gameForm.platform}
                      onChange={(e) => setGameForm({...gameForm, platform: e.target.value})}
                      style={{ width: '100%', padding: '0.5rem 0.75rem', backgroundColor: '#374151', color: 'white', borderRadius: '0.375rem', border: 'none' }}
                    >
                      <option value="PC">PC</option>
                      <option value="Mobile">Mobile</option>
                      <option value="Console">Console</option>
                    </select>
                  </div>
                  <div style={{ display: 'flex', gap: '1rem' }}>
                    <button
                      type="submit"
                      style={{ backgroundColor: '#DC2626', color: 'white', padding: '0.5rem 1.5rem', borderRadius: '0.375rem', fontWeight: 'medium', border: 'none', cursor: 'pointer' }}
                    >
                      حفظ اللعبة
                    </button>
                    <button
                      type="button"
                      onClick={() => setShowAddForm(false)}
                      style={{ backgroundColor: '#6B7280', color: 'white', padding: '0.5rem 1.5rem', borderRadius: '0.375rem', fontWeight: 'medium', border: 'none', cursor: 'pointer' }}
                    >
                      إلغاء
                    </button>
                  </div>
                </form>
              </div>
            )}

            <div style={{ backgroundColor: '#1F2937', borderRadius: '0.5rem', overflow: 'hidden' }}>
              <div style={{ padding: '1rem', borderBottom: '1px solid #374151' }}>
                <h2 style={{ fontSize: '1.25rem', fontWeight: 'bold' }}>قائمة الألعاب</h2>
                <p style={{ color: '#9CA3AF' }}>إدارة الألعاب المتوفرة في المتجر</p>
              </div>

              {loading ? (
                <div style={{ padding: '2rem', textAlign: 'center' }}>
                  <div style={{ display: 'inline-block', width: '2rem', height: '2rem', border: '2px solid #DC2626', borderTopColor: 'transparent', borderRadius: '50%', animation: 'spin 1s linear infinite' }}></div>
                  <p style={{ marginTop: '0.5rem' }}>جاري التحميل...</p>
                </div>
              ) : (
                <div style={{ overflowX: 'auto' }}>
                  <table style={{ width: '100%', borderCollapse: 'collapse' }}>
                    <thead style={{ backgroundColor: '#374151' }}>
                      <tr>
                        <th style={{ padding: '0.75rem 1.5rem', textAlign: 'right', fontSize: '0.75rem', fontWeight: 'medium', color: '#D1D5DB', textTransform: 'uppercase' }}>صورة</th>
                        <th style={{ padding: '0.75rem 1.5rem', textAlign: 'right', fontSize: '0.75rem', fontWeight: 'medium', color: '#D1D5DB', textTransform: 'uppercase' }}>اسم اللعبة</th>
                        <th style={{ padding: '0.75rem 1.5rem', textAlign: 'right', fontSize: '0.75rem', fontWeight: 'medium', color: '#D1D5DB', textTransform: 'uppercase' }}>السعر</th>
                        <th style={{ padding: '0.75rem 1.5rem', textAlign: 'right', fontSize: '0.75rem', fontWeight: 'medium', color: '#D1D5DB', textTransform: 'uppercase' }}>المنصة</th>
                        <th style={{ padding: '0.75rem 1.5rem', textAlign: 'right', fontSize: '0.75rem', fontWeight: 'medium', color: '#D1D5DB', textTransform: 'uppercase' }}>الحالة</th>
                        <th style={{ padding: '0.75rem 1.5rem', textAlign: 'right', fontSize: '0.75rem', fontWeight: 'medium', color: '#D1D5DB', textTransform: 'uppercase' }}>الإجراءات</th>
                      </tr>
                    </thead>
                    <tbody style={{ borderBottom: '1px solid #374151' }}>
                      {games.map((game) => (
                        <tr key={game._id} style={{ backgroundColor: '#111827' }}>
                          <td style={{ padding: '1rem 1.5rem', whiteSpace: 'nowrap' }}>
                            <div style={{ flexShrink: 0, height: '4rem', width: '4rem' }}>
                              <img
                                style={{ height: '4rem', width: '4rem', borderRadius: '0.5rem', objectFit: 'cover' }}
                                src={game.image}
                                alt={game.title}
                              />
                            </div>
                          </td>
                          <td style={{ padding: '1rem 1.5rem', whiteSpace: 'nowrap' }}>
                            <div style={{ fontSize: '0.875rem', fontWeight: 'medium', color: 'white' }}>{game.title}</div>
                            <div style={{ fontSize: '0.875rem', color: '#9CA3AF' }}>{game.category}</div>
                          </td>
                          <td style={{ padding: '1rem 1.5rem', whiteSpace: 'nowrap' }}>
                            <div style={{ fontSize: '0.875rem', color: 'white' }}>
                              ${game.price}
                              {game.discount && game.originalPrice && (
                                <div style={{ fontSize: '0.75rem', color: '#9CA3AF', textDecoration: 'line-through' }}>
                                  ${game.originalPrice}
                                </div>
                              )}
                            </div>
                            {game.discount && (
                              <div style={{ fontSize: '0.75rem', color: '#10B981' }}>
                                -{game.discount}%
                              </div>
                            )}
                          </td>
                          <td style={{ padding: '1rem 1.5rem', whiteSpace: 'nowrap' }}>
                            <div style={{ display: 'flex', alignItems: 'center' }}>
                              {game.platform === 'PC' && (
                                <svg style={{ height: '1.25rem', width: '1.25rem', color: '#3B82F6' }} fill="currentColor" viewBox="0 0 20 20">
                                  <path d="M3 4a1 1 0 011-1h12a1 1 0 011 1v2a1 1 0 01-1 1H4a1 1 0 01-1-1V4zM3 10a1 1 0 011-1h6a1 1 0 011 1v6a1 1 0 01-1 1H4a1 1 0 01-1-1v-6zM14 9a1 1 0 00-1 1v6a1 1 0 001 1h2a1 1 0 001-1v-6a1 1 0 00-1-1h-2z" />
                                </svg>
                              )}
                              {game.platform === 'Mobile' && (
                                <svg style={{ height: '1.25rem', width: '1.25rem', color: '#10B981' }} fill="currentColor" viewBox="0 0 20 20">
                                  <path d="M7 2a2 2 0 00-2 2v12a2 2 0 002 2h6a2 2 0 002-2V4a2 2 0 00-2-2H7zm3 14a1 1 0 100-2 1 1 0 000 2z" />
                                </svg>
                              )}
                              <span style={{ marginRight: '0.5rem', fontSize: '0.875rem', color: '#D1D5DB' }}>{game.platform}</span>
                            </div>
                          </td>
                          <td style={{ padding: '1rem 1.5rem', whiteSpace: 'nowrap' }}>
                            <span style={{
                              padding: '0.25rem 0.5rem',
                              fontSize: '0.75rem',
                              fontWeight: 'semibold',
                              borderRadius: '9999px',
                              backgroundColor: game.availability === 'available' ? '#10B981' : '#EF4444',
                              color: 'white'
                            }}>
                              {game.availability === 'available' ? 'متاحة' : 'غير متاحة'}
                            </span>
                          </td>
                          <td style={{ padding: '1rem 1.5rem', whiteSpace: 'nowrap', fontSize: '0.875rem', fontWeight: 'medium' }}>
                            <div style={{ display: 'flex', gap: '0.5rem' }}>
                              <button
                                onClick={() => handleEditPrice(game._id)}
                                style={{ color: '#3B82F6', backgroundColor: 'transparent', border: 'none', cursor: 'pointer', padding: '0.25rem' }}
                                title="تعديل السعر"
                              >
                                <svg style={{ width: '1.25rem', height: '1.25rem' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z" />
                                </svg>
                              </button>
                              <button
                                onClick={() => handleAddDiscount(game._id)}
                                style={{ color: '#10B981', backgroundColor: 'transparent', border: 'none', cursor: 'pointer', padding: '0.25rem' }}
                                title="إضافة خصم"
                              >
                                <svg style={{ width: '1.25rem', height: '1.25rem' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                                </svg>
                              </button>
                              <button
                                onClick={() => handleDeleteGame(game._id)}
                                style={{ color: '#EF4444', backgroundColor: 'transparent', border: 'none', cursor: 'pointer', padding: '0.25rem' }}
                                title="حذف اللعبة"
                              >
                                <svg style={{ width: '1.25rem', height: '1.25rem' }} fill="none" stroke="currentColor" viewBox="0 0 24 24">
                                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                                </svg>
                              </button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              )}
            </div>
          </div>
        )}

        {activeTab === 'users' && (
          <div style={{ backgroundColor: '#1F2937', padding: '1.5rem', borderRadius: '0.5rem' }}>
            <h2 style={{ fontSize: '1.25rem', fontWeight: 'bold', marginBottom: '1rem' }}>إدارة المستخدمين</h2>
            <p style={{ color: '#9CA3AF' }}>سيتم تنفيذ هذه الميزة قريباً</p>
          </div>
        )}

        {activeTab === 'orders' && (
          <div style={{ backgroundColor: '#1F2937', padding: '1.5rem', borderRadius: '0.5rem' }}>
            <h2 style={{ fontSize: '1.25rem', fontWeight: 'bold', marginBottom: '1rem' }}>إدارة الطلبات</h2>
            <p style={{ color: '#9CA3AF' }}>سيتم تنفيذ هذه الميزة قريباً</p>
          </div>
        )}
      </div>
    </div>
  );
};

const App = () => {
  return (
    <Router>
      <AuthProvider>
        <NavigationProvider>
          <div style={{ minHeight: '100vh', backgroundColor: '#111827', color: 'white' }}>
            <Navbar />
            <main style={{ maxWidth: '1200px', margin: '0 auto', padding: '2rem 1rem' }}>
              <Routes>
                <Route path="/" element={<Home />} />
                <Route path="/login" element={<Login />} />
                <Route path="/register" element={<Register />} />
                <Route path="/game/:id" element={<GameDetail />} />
                <Route path="/cart" element={<Cart />} />
                <Route path="/profile" element={<Profile />} />
                <Route path="/favorites" element={<Favorites />} />
                <Route path="/google/callback" element={<GoogleCallback />} />
                <Route path="/test-backend" element={<TestBackend />} />
                <Route path="/admin" element={<AdminDashboard />} />
                <Route path="*" element={<Navigate to="/" replace />} />
              </Routes>
            </main>
            <Notifications />
          </div>
        </NavigationProvider>
      </AuthProvider>
    </Router>
  );
};

